var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_B","text":{"KOREA":"저 녀석들…. 관리국에서 온 녀석들이잖아?","JPN":"あいつら……管理局のやつらだ。","ENG":"Aren't those people... from the Administration?","TWN":"那些…是管理局的人吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_STAY_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_A","text":{"KOREA":"게다가 시니어까지 온 모양이야. 분위기가 심상치 않은데.","JPN":"しかもシニアまで来たようだぞ。尋常じゃねえな。","ENG":"I heard there's a Senior there as well. Things aren't looking so good, are they?","TWN":"而且連Senior都出馬咧，感覺不太對喔。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_STAY_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_NPC_STAY_A","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 여기 관리국에 찍힌 회사였어?","JPN":"まさかここ、管理局に目をつけられてる会社だったのか？","ENG":"Wait a sec... this company's on bad terms with the Administration?","TWN":"難道這間公司被管理局盯上了嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장…. 이래서 헤드헌터들은 믿을 게 못 된다니까.","JPN":"くそ……これだからヘッドハンターは信用できないんだよ。","ENG":"Dammit... Should've known better than to listen to headhunters.","TWN":"可惡…那些獵人頭的話真的不可信！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으, 응? 분위기가 갑자기 왜 이래? 뭐가 어떻게 돌아가는 거야?","JPN":"う、うん？　この雰囲気は何？　何がどうなってるのよ？","ENG":"H-huh? What's happening? Why's everyone leaving all of a sudden?","TWN":"欸？嗯？氣氛怎麼突然變這樣？是發生什麼事？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_A","text":{"KOREA":"이봐, 슈퍼 루키! 경력 절단 나고 싶지 않으면 빨리 움직여!","JPN":"おい、スーパールーキー！　キャリア中断になりたくなかったら早く動け！","ENG":"Hey, Super Rookie! If you don't want your career to end, you'd better move fast too!","TWN":"喂，超級新生！不想履歷表上有汙點的話，就趕快閃人吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_NPC_STAY_B","text":{"KOREA":"뭐 해, 어서 가자고!","JPN":"何してんだよ、早く行こうぜ！","ENG":"C'mon! We gotta get outta here!","TWN":"還想什麼？快走吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우, 우와악! 밀지 마! 밀지 말라니까, 이 인간들아!","JPN":"う、うわああ！　押さないで！　押さないでってば、こら！","ENG":"W-whoa! Don't push! I said, stop pushing!","TWN":"欸欸欸！不要推啦！喂，就叫你們不要推！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"내 면접을 방해하는 거냐! 저리 비키지 못해?! 야!! 잠깐만요! 야!","JPN":"私の面接を邪魔する気！　どきなさいよ！！　ちょっと！！　待ちなさい！　ちょっと！","ENG":"Get out of my way! Why are you interfering with my interview?! H-hey! WAIT!!","TWN":"想妨礙我面試是不是！還不給我滾開？！走開啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"갸아아아아악!","JPN":"ぎゃあああああ！","ENG":"GAAAH!","TWN":"啊啊啊啊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"늦어서 죄송합니다! 지금부터 번호대로 면접 진행하도록 하겠습니다!","JPN":"遅くなって申し訳ありません！　今から番号順に面接を開始します！","ENG":"We're terribly sorry for the delay! We will begin the interviews in order!","TWN":"抱歉，讓大家久等了！接下來就會按照號碼開始進行面試！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…아무도 없어. 배가 고파서 다들 갔나 봐.","JPN":"……誰もいない。お腹が空いてみんな帰ったみたい。","ENG":"No one's here. Maybe they got hungry and left.","TWN":"…一個人都沒有，可能是肚子餓先走了吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"채용은 포기하셔야겠네요, 사장님.","JPN":"採用はあきらめないといけませんね、社長。","ENG":"I guess we should give up hiring, Boss.","TWN":"老闆，看來是要放棄徵人了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"관리국과 트러블이 생긴 회사에 지원할 바보는 세상에 한 명뿐일 걸요.","JPN":"管理局とトラブルのある会社に志願するバカはこの世界に一人しかいないと思うけど。","ENG":"There's only one person I know who would apply for a company that is on bad terms with the Administration.","TWN":"明知道公司和管理局不合還願意來面試的人，全世界只有一個。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"야, 왜 날 보고 말하냐? 듣는 사람 기분 나쁘게.","JPN":"おい、なんでこっち見ながら言ってんだよ？　気分悪いだろ。","ENG":"Huh? Why are you looking at me for? I feel offended.","TWN":"喂，你幹嘛看著我講？感覺很差欸！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아직 한 명 남아 있군. 저 아가씨는 어떤가?","JPN":"まだ一人残っているな。あのお嬢さんはどうだ？","ENG":"There's still one applicant left. How about that girl?","TWN":"還有一個人。那位小姐怎麼樣？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"코오──","JPN":"コォ――","ENG":"Cof──","TWN":"科──"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"피인───.","JPN":"フィーン―――","ENG":"Fin───.","TWN":"芬───"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"코오──.","JPN":"コォ――","ENG":"Coff──.","TWN":"科──"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"희한하네. 요즘 애들은 자면서 이런 소리를 내나.","JPN":"変わってるわね。今時の子どもって、寝ながらこんな音出すのかしら？","ENG":"That's strange. Do kids these day snore like that?","TWN":"好奇妙，最近的孩子睡覺會發出那種怪聲嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저기요? 일어나 보실래요? 저기요?","JPN":"あの？　起きてくれませんか？　あのぉ？","ENG":"Excuse me? Could you wake up? Hello?","TWN":"哈囉？可以請你醒醒嗎？哈囉？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흠냐….","JPN":"むにゃ……","ENG":"*Smacks her lips*","TWN":"哈啊…"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐앗!? 깜빡 잠들어 버렸어요!","JPN":"ふあっ！？　うっかり寝てしまいました！","ENG":"H-huh?! I fell asleep!","TWN":"哇啊！？我不小心睡著了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"지금 몇 시죠?! 면접 끝난 거 아니죠?","JPN":"今何時ですか！？　面接終わってないですよね？","ENG":"What time is it? Are the interviews already over?!","TWN":"現在幾點啦？！面試還沒結束吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 아앗. 아무도 없어…. 설마 조느라 부르는 소리도 못 들었던 건….","JPN":"あ、ああっ。誰もいない……まさか寝てたせいで呼ばれたのもわからなかったんじゃ……？","ENG":"H-huh? No one's here... Did I miss my number while I was snoozing...?","TWN":"怎，怎麼都沒人…該不會是我睡著了沒聽到有人叫我吧…"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"진정하세요. 면접은 지금부터 시작이니까요.","JPN":"落ち着いてください。面接は今からですので。","ENG":"Calm down. The interview's going to start now.","TWN":"請你先冷靜一點，現在才剛開始要面試而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네?! 정말요?!","JPN":"え！？　本当ですか！？","ENG":"What? Really?!","TWN":"喔？！真的嗎？！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다행이다~ 잠들어 있던 사이에 끝난 줄 알고 가슴이 철렁했거든요~","JPN":"よかった～寝ている間に終わったのかと思ってヒヤッとしました～","ENG":"Phew! My heart skipped a beat thinking I missed it!","TWN":"好險～我還以為我睡到錯過面試，心臟漏跳一拍呢～"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아하하…….","JPN":"あはは……","ENG":"Ah ha ha...","TWN":"哈哈……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"시작부터 불안하네요, 어째.","JPN":"最初からなんだか先が思いやられますね。","ENG":"Why am I getting a bad feeling about this...?","TWN":"怎麼才要開始而已就有不好的預感。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 지금부터, 펜릴 소대 지원자인 노엘 라이트 양의 면접을 진행하도록 하겠습니다.","JPN":"それでは今から、フェンリル小隊の志願者であるノエル・ライトさんの面接を行います。","ENG":"Our interview with Noelle Wright, an applicant for Fenrir Squad, will begin.","TWN":"現在開始芬里爾小隊員招募面試，應徵者是洛艾兒·萊特。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"면접관은 저희 회사 사장님과 부사장님, 펜릴 소대 소대장 대리인 유미나 소대원 두 분입니다.","JPN":"面接官は我が社の社長、副社長、フェンリル小隊長代行のヤナギ・ミナ隊員です。","ENG":"You will be interviewed by our Boss, Vice President, and Fenrir Squad Commander representative Yoo Mina.","TWN":"面試官有三位，分別是我們公司老闆、副總，以及芬里爾小隊長代理人劉米娜小隊員。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 부탁하네, 노엘 양.","JPN":"よろしく頼むよ、ノエル君。","ENG":"Pleased to meet you, Noelle.","TWN":"請多指教囉，洛艾兒小姐。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 저도요!","JPN":"はい！　こちらこそ！","ENG":"Pleased to meet you too!","TWN":"是！請多指教！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"유미나 님도 잘 부탁드려요!","JPN":"ミナ様もよろしくお願いします！","ENG":"Nice to meet you as well, Ms. Mina!","TWN":"劉米娜小姐也請多指教！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"어? 나 말이야?","JPN":"え？　私？","ENG":"Oh? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 꼭 만나고 싶었어요!","JPN":"はい！　ぜひ会ってみたかったんです！","ENG":"Yes! I always wanted to meet you in person!","TWN":"是！久仰您的大名！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"전 펜릴 소대의 팬이거든요. 온라인 쇼핑몰에 출시된 굿즈도 전부 사 모았어요.","JPN":"私、フェンリル小隊の大ファンなんです。ネットで販売されているグッズも全部買い揃えました。","ENG":"You see, I'm a huge fan of Fenrir Squad. I even bought all the merchandise sold in the online shopping mall!","TWN":"我是芬里爾小隊的粉絲，網購出的周邊商品我全都有收集喔！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"굿즈라고……?","JPN":"グッズ……？","ENG":"Merchandise...?","TWN":"周邊商品……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"펜릴 소대 마크가 들어간 텀블러나 스승님의 브로마이드를 말하는 겁니다.","JPN":"フェンリル小隊のマーク入りのタンブラーや、師匠のブロマイドのことです。","ENG":"She's referring to a tumbler with the Fenrir Squad's logo and a poster of Master.","TWN":"像是有芬里爾小隊標誌的保溫杯，或是師父的海報。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"유행에 편승해 사업 포트폴리오를 확장하기 위한 야심찬 계획이었죠.","JPN":"流行に便乗し、事業を拡張するための大胆な計画でした。","ENG":"It was an ambitious plan to expand our business portfolio by following the latest trends.","TWN":"這是一個趁流行擴大事業體的偉大計劃。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제는 그것 때문에 성대한 빚 잔치를 벌이게 생겼지만요.","JPN":"今はそのせいで借金地獄に陥る一歩手前ですがね。","ENG":"But now, it seems that we will be in a lot of debt because of that.","TWN":"不過現在因為這些周邊，會害得我們公司負債累累。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"관리국에 찍힌 태스크포스의 굿즈 따위, 아무도 안 사 줄 테니 말입니다.","JPN":"管理局に目をつけられたタスクフォースのグッズなんて、誰も買わないでしょうから。","ENG":"No one is going to buy merchandise of a TASKFORCE that is out of favor with the Administration.","TWN":"畢竟誰會想要買被管理局盯上的特遣勢力周邊。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 그래…….","JPN":"あ、そう……","ENG":"Oh, right...","TWN":"喔，是喔……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"옷은 쇼핑몰에 안 팔아서 제가 직접 만들었습니다!","JPN":"服はサイトで売ってなくて、私が直接作りました！","ENG":"There were no uniforms to sell in the shopping mall, so I made this one on my own!","TWN":"這件衣服網購上沒有賣，是我自己親手做的喔！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"대신 아이 러브 펜릴 팬티는 샀어요. 보실래요?","JPN":"その代わり、アイ・ラブ・フェンリルの下着は買いましたよ。見ます？","ENG":"I did, however, purchase the \\"I Love Fenrir\\" underwear. You wanna see?","TWN":"不過我有買我愛芬里爾小褲褲，你們要看嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"…저런 굿즈도 팔았나, 부사장?","JPN":"……そんなグッズまで売っていたのか？　副社長。","ENG":"You even sold that too, Vice President?","TWN":"…副總，你連這種周邊也有賣嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"훌륭한 열정이군.","JPN":"たいした情熱だな。","ENG":"Now that's passion.","TWN":"令人讚嘆的熱情呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"노이즈 마케팅용으로 내놓은 한정품입니다. 정말 사는 사람이 있었네요.","JPN":"ノイズマーケティング用に出した限定品です。本当に買う人がいるんですね。","ENG":"It was a limited-run product that we used for outrage marketing. I didn't know anyone would really buy it.","TWN":"那是拿來炒作用的限定商品，沒想到還真的有人買。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양, 노엘 양에게 질문해 보세요.","JPN":"ミナさん、ノエルさんに質問してください。","ENG":"Mina, ask Noelle a question.","TWN":"米娜，請你向洛艾兒小姐提問。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"면접의 당락을 결정하려면 절차는 제대로 걸쳐야죠.","JPN":"面接の合否を決定するためには、しっかり面接しないといけませんから。","ENG":"In order to determine the interview, we must take the necessary steps.","TWN":"要面試過才知道要不要錄取吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"관리부장님이 아무 말 안 했어?","JPN":"管理部長から聞いてない？","ENG":"Didn't the Manager tell you?","TWN":"管理部長沒說嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"난 딱히 소대원을 새로 뽑을 생각 없다니까.","JPN":"私は別に新しい小隊員を選ぶつもりはないよ。","ENG":"I don't want to hire another squad member.","TWN":"我不想徵新人進來。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"당락을 결정하려면 최소한의 절차를 밟게나.","JPN":"合否を決定するためにも質問くらいはしてくれないか。","ENG":"We must still do the minimum to decide this interview's outcome.","TWN":"不管要不要用她，還是要走完最基本的流程。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"혹시 모르지 않나. 마음이 잘 맞을지.","JPN":"わからないぞ。ひょっとしたら気が合うかもしれない。","ENG":"Who knows? You might like her.","TWN":"話先別說得這麼早，或許你會喜歡她呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아……. 알겠어.","JPN":"はあ……わかったよ。","ENG":"*Sigh...* Fine.","TWN":"哀……好吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘이라고 했지? 질문할 테니까 대답하든 말든 마음대로 해.","JPN":"ノエルだっけ？　質問するから答えるかどうか勝手にして。","ENG":"Noelle, right? I'm gonna ask you a question, and you can choose whether or not to answer it.","TWN":"你叫洛艾兒對吧？我會問你問題，至於要不要回答隨便你。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"뭐든지 물어봐 주세요! 전부 대답해 드릴게요!","JPN":"何でも聞いてください！　全部答えます！","ENG":"Ask me anything! I'll answer them all!","TWN":"請儘管問吧！我有問必答！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};